import React from "react";
import { Card } from "flowbite-react";

const Movies = () => {
  return (
    <div className="mx-auto shadow mt-6  container">
      <div className=" grid md:grid-cols-2 lg:grid-cols-4 gap-4 justify-center">
        <div className="" >
          <card className=" border border-collapse " >
            <img className="mb-6 w-75 h-100"
              src="https://msp.c.yimg.jp/images/v2/FUTi93tXq405grZVGgDqGyXtFeY7do_C95WjwnQfNHZWchNkW6r_u1Znuql6-HifkKMFP0Dz8dY4-Fhrl3--BRuZh2Mezn5VCmwNH7F1qanPT6WPSHctAGhAvxhMRezg7HQCHBHnKBcqfqxrBzHp29xhPrqbOFe6oFNoFeFyiO6DY-_0IZgJrIWy3x9FIJ5TBa6gNuNs_GmOQrEVcl9wBJzU-mt4UhJnxCOPaJAzUc2JnHzukWlMbg6dxOSJsgh7C3MWCp5fQDmkKbGacLRzHEVKV7gASStXQE25nZcgxhaIa-OTgcc8scf8PDbl8eX4-Z11h8BQjR8Q4QBfClXMywyg-fK2FAQecbfSbgzM0YxqccJzceNd_TYm_NyxKB_0hAymUjJ__TGeEBghJlGvbw==/depositphotos_150614902-stock-photo-unusual-cinema-concept-3d-illustration.jpg?errorImage=false"
              alt=""
            />
            <span className="text-2xl font-bold text-center ">Cinema</span>
            <p className="">
              Streamlining your design process today. In today’s fast-paced
              digital landscape, fostering seamless collaboration among
              Developers and IT Operations.
            </p>
          </card>
        </div>
      </div>
    </div>
  );
};  

export default Movies;
